DIST_MAX_2OBS = 50


def getMerges(edge, collection, DIST_MAX_2OBS):

    s = edge.geom.getFirstObs()
    t = edge.geom.getLastObs()
    
    
    def sommets_proches(t1, t2):
        p1 = t1.getFirstObs()
        p2 = t1.getLastObs()
    
        o1 = t2.getFirstObs()
        o2 = t2.getLastObs()
    
        if o1.distance2DTo(p1) < DIST_MAX_2OBS and o2.distance2DTo(p2) < DIST_MAX_2OBS:
            return False
        if o2.distance2DTo(p1) < DIST_MAX_2OBS and o1.distance2DTo(p2) < DIST_MAX_2OBS:
            return False
    
        if o1.distance2DTo(p1) < DIST_MAX_2OBS:
            return True
        if o2.distance2DTo(p1) < DIST_MAX_2OBS:
            return True
        if o1.distance2DTo(p2) < DIST_MAX_2OBS:
            return True
        if o2.distance2DTo(p2) < DIST_MAX_2OBS:
            return True
        return False
    
    
    def merge(t1, t2):
        p1 = t1.getFirstObs()
        p2 = t1.getLastObs()
    
        o1 = t2.getFirstObs()
        o2 = t2.getLastObs()
    
        if o1.distance2DTo(p1) < DIST_MAX_2OBS:
            return t1.reverse() + t2
        if o2.distance2DTo(p1) < DIST_MAX_2OBS:
            return t2 + t1
        if o1.distance2DTo(p2) < DIST_MAX_2OBS:
            return t1 + t2
        if o2.distance2DTo(p2) < DIST_MAX_2OBS:
            return t1 + t2.reverse()
    
        return None
    
    
    TRAITEES = []
    for track in collection:
    
        PROXGROUPS = []
    
        # chercher les traces contenant des segments proches
        for t in TRAITEES:
            if sommets_proches(t, track):
                PROXGROUPS.append(t)
                break
    
        if len(PROXGROUPS) == 0:
            # créer un nouveau groupe
            TRAITEES.append(track)
    
        elif len(PROXGROUPS) == 1:
            t1  = PROXGROUPS[0]
            TRAITEES.remove(t1)
            # ajouter au groupe existant
            newtrack = merge(t1, track)
            TRAITEES.append(newtrack)
    
        else:
            # fusionner les groupes
            nouveau = track
            for t1 in PROXGROUPS:
                TRAITEES.remove(t1)
                newtrack = merge(t1, track)
    
            TRAITEES.append(newtrack)

    return TRAITEES


TRAITEES = getMerges(edge, collection, DIST_MAX_2OBS)

print (len(TRAITEES))

for t in TRAITEES:
    t.plot('b-')
